import React from 'react'
import ServiceCard from './ServiceCard/ServiceCard'

import './NossosServicos.css'

const NossosServicos = ({ services }) => {
    return (
        <section id="nossosServicos">
            <h2>conheça nossos serviços</h2>

            <div id="services">

                {/* <ServiceCard img={Michel} serviceName={"Segurança"}></ServiceCard>
                <ServiceCard img={Michel} serviceName={"Eletronica"}></ServiceCard>
                <ServiceCard img={Michel} serviceName={"Portaria"}></ServiceCard>
                <ServiceCard img={Michel} serviceName={"Spp"}></ServiceCard>
                <ServiceCard img={Michel} serviceName={"Patrimonial"}></ServiceCard> */}

                {services.map((item, index) => (

                    <ServiceCard key={index} img={item.img} serviceName={item.title}></ServiceCard>

                ))}

            </div>

        </section>
    )
}

export default NossosServicos
